<!-- ══════════════ LOGIN ══════════════ -->
<section id="loginScreen" class="login-screen">
  <div class="login-card">
    <div class="brand">
      <div class="logo" style="background:#000;padding:2px"><img src="data:image/png;base64," style="width:100%;height:100%;object-fit:contain;border-radius:12px" alt="Remap" /></div>
      <div>
        <h1>HUB Remap</h1>
        <p>Controle de tempo por cliente, tarefa e cargo.</p>
      </div>
    </div>
    <label for="loginName">Nome do colaborador</label>
    <input id="loginName" placeholder="Ex: João Silva" />
    <label for="loginPass">Senha</label>
    <input id="loginPass" type="password" placeholder="Digite sua senha" />
    <button class="btn-primary" style="margin-top:20px" onclick="login()">Entrar</button>
  </div>
</section>
